trigger PreventDuplicateContactEmails on Contact (before insert, before update) {
    Set<String> emailsInBatch = new Set<String>();
    for (Contact c : Trigger.new) {
        if (String.isNotBlank(c.Email)) {
            emailsInBatch.add(c.Email.toLowerCase());
        }
    }

    if (emailsInBatch.isEmpty()) return;

    Map<String, Contact> existingByEmail = new Map<String, Contact>();
    for (Contact c : [
        SELECT Id, Email FROM Contact
        WHERE Email IN :emailsInBatch
        AND Id NOT IN :Trigger.newMap.keySet()
    ]) {
        existingByEmail.put(c.Email.toLowerCase(), c);
    }

    for (Contact c : Trigger.new) {
        if (String.isNotBlank(c.Email) &&
            existingByEmail.containsKey(c.Email.toLowerCase())) {
            c.Email.addError('A Contact with this email address already exists.');
        }
    }
}

public class AccountRatingBatch implements Database.Batchable<SObject> {

    public Database.QueryLocator start(Database.BatchableContext bc) {
        return Database.getQueryLocator(
            'SELECT Id, Rating, ' +
            '(SELECT Amount FROM Opportunities WHERE StageName = \'Closed Won\') ' +
            'FROM Account'
        );
    }

    public void execute(Database.BatchableContext bc, List<Account> scope) {
        List<Account> toUpdate = new List<Account>();

        for (Account acc : scope) {
            Decimal total = 0;
            for (Opportunity opp : acc.Opportunities) {
                if (opp.Amount != null) total += opp.Amount;
            }

            String newRating;
            if (total >= 1000000) newRating = 'Hot';
            else if (total >= 100000) newRating = 'Warm';
            else newRating = 'Cold';

            if (acc.Rating != newRating) {
                acc.Rating = newRating;
                toUpdate.add(acc);
            }
        }

        if (!toUpdate.isEmpty()) {
            update toUpdate;
        }
    }

    public void finish(Database.BatchableContext bc) {
        System.debug('AccountRatingBatch complete.');
    }
}

@isTest
private class PreventDuplicateAccountsTest {

    @TestSetup
    static void setup() {
        Account existing = new Account(Name = 'Acme Corp');
        insert existing;
    }

    @isTest
    static void testInsertDuplicateNameFails() {
        Account duplicate = new Account(Name = 'Acme Corp');
        try {
            insert duplicate;
            System.assert(false, 'Expected exception was not thrown');
        } catch (DmlException e) {
            System.assert(
                e.getMessage().contains('already exists'),
                'Error message should mention duplicate: ' + e.getMessage()
            );
        }
    }

    @isTest
    static void testInsertUniqueNameSucceeds() {
        Account unique = new Account(Name = 'Unique Company XYZ');
        Test.startTest();
        insert unique;
        Test.stopTest();
        System.assertNotEquals(null, unique.Id, 'Account should have been inserted');
    }

    @isTest
    static void testUpdateToDuplicateNameFails() {
        Account newAcc = new Account(Name = 'Beta Corp');
        insert newAcc;

        newAcc.Name = 'Acme Corp';
        try {
            update newAcc;
            System.assert(false, 'Expected exception was not thrown');
        } catch (DmlException e) {
            System.assert(e.getMessage().contains('already exists'), 'Should get duplicate error');
        }
    }
}
